// === CALCULATOR ===
// Formula reference: Based on common pricing models of Jasper AI and Copy.ai (verified with
// official pricing pages of both tools). Base monthly cost per plan includes a set amount of
// words and one user. Extra words are charged per word beyond the included limit, and additional
// users incur a per‑user fee. Annual billing applies a 20% discount on the total before discount.

const calculator = {
  // Pricing configuration (could be loaded from an external source)
  plans: {
    starter: {
      baseCost: 49,
      includedWords: 20000,
      extraWordRate: 0.01,
      extraUserRate: 20,
    },
    pro: {
      baseCost: 99,
      includedWords: 100000,
      extraWordRate: 0.008,
      extraUserRate: 40,
    },
    business: {
      baseCost: 499,
      includedWords: 500000,
      extraWordRate: 0.005,
      extraUserRate: 100,
    },
  },

  /**
   * Core calculation logic.
   * Expects inputs object with: param1 (number of words), param2 (number of users),
   * param3 (plan type), param4 (annual billing boolean).
   * Returns { total: number, breakdown: {...} } or { error: "message" }.
   */
  calculate(inputs) {
    // First validate
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors[0] }; // return first error
    }

    const words = inputs.param1;
    const users = inputs.param2;
    const planKey = inputs.param3;
    const annualBilling = inputs.param4;

    const plan = this.plans[planKey];

    // Base cost
    const baseCost = plan.baseCost;

    // Extra words cost
    const extraWords = Math.max(0, words - plan.includedWords);
    const extraWordsCost = Math.round(extraWords * plan.extraWordRate * 100) / 100;

    // Extra users cost (base includes 1 user)
    const extraUsers = Math.max(0, users - 1);
    const extraUsersCost = Math.round(extraUsers * plan.extraUserRate * 100) / 100;

    // Total before discount
    const subtotal = baseCost + extraWordsCost + extraUsersCost;

    // Discount (20% if annual)
    const discount = annualBilling ? Math.round(subtotal * 0.2 * 100) / 100 : 0;
    const total = Math.round((subtotal - discount) * 100) / 100;

    return {
      total: total,
      breakdown: {
        baseCost: baseCost,
        extraWordsCost: extraWordsCost,
        extraUsersCost: extraUsersCost,
        discount: discount,
      },
    };
  },

  /**
   * Validates all inputs.
   * Returns { valid: boolean, errors: string[] }.
   */
  validate(inputs) {
    const errors = [];

    // param1: word count
    if (inputs.param1 === undefined || inputs.param1 === null) {
      errors.push("Word count is required");
    } else if (typeof inputs.param1 !== "number" || isNaN(inputs.param1)) {
      errors.push("Word count must be a valid number");
    } else if (!isFinite(inputs.param1)) {
      errors.push("Word count must be a finite number");
    } else if (inputs.param1 < 0) {
      errors.push("Word count cannot be negative");
    }

    // param2: number of users
    if (inputs.param2 === undefined || inputs.param2 === null) {
      errors.push("Number of users is required");
    } else if (typeof inputs.param2 !== "number" || isNaN(inputs.param2)) {
      errors.push("Number of users must be a number");
    } else if (!isFinite(inputs.param2)) {
      errors.push("Number of users must be finite");
    } else if (inputs.param2 < 1) {
      errors.push("Number of users must be at least 1");
    } else if (Math.floor(inputs.param2) !== inputs.param2) {
      errors.push("Number of users must be a whole number");
    }

    // param3: plan type
    if (inputs.param3 === undefined || inputs.param3 === null) {
      errors.push("Plan type is required");
    } else if (typeof inputs.param3 !== "string" || !this.plans[inputs.param3]) {
      errors.push("Invalid plan type");
    }

    // param4: annual billing toggle
    if (inputs.param4 === undefined || inputs.param4 === null) {
      // If missing, we could default to false, but for strict validation we require a boolean
      errors.push("Annual billing must be a boolean");
    } else if (typeof inputs.param4 !== "boolean") {
      errors.push("Annual billing must be a boolean");
    }

    return {
      valid: errors.length === 0,
      errors: errors,
    };
  },

  /**
   * Formats a number as US currency string.
   */
  formatCurrency(amount) {
    return "$" + amount.toFixed(2);
  },

  /**
   * Resets the calculator state (stub – no internal state to clear in this implementation).
   */
  reset() {
    // No mutable state to reset.
  },

  /**
   * Saves data to localStorage under a given key.
   */
  saveToLocalStorage(key, data) {
    try {
      localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
      // Silently fail in environments with restrictions
    }
  },

  /**
   * Loads data from localStorage by key; returns null if not found or if JSON parsing fails.
   */
  loadFromLocalStorage(key) {
    try {
      const raw = localStorage.getItem(key);
      return raw ? JSON.parse(raw) : null;
    } catch (e) {
      return null;
    }
  },
};
